diagram_versions.activity diagram:
@startuml
title E-commerce Checkout Workflow

start

partition "Client Application" {
  :User initiates Checkout;
  -> Request Checkout;
}

partition "API Gateway Service" {
  :Route Request;
  -> Authenticate User;
}

partition "Auth Service" {
  :Validate User Session/Token;
  if (User Authenticated?) then (Yes)
    -> User Validated;
  else (No)
    :Return Authentication Error;
    stop
  endif
}

partition "Shopping Cart Service" {
  :Retrieve Cart Items;
  -> Cart Items Retrieved;
}

partition "User Profile Service" {
  :Retrieve Shipping Address;
  -> Shipping Address Retrieved;
}

partition "Order Service" {
  :Create Pending Order Record;
  -> Order Record Created;
}

fork
  partition "Inventory Service" {
    :Check Stock & Reserve Items;
    if (Items in Stock?) then (Yes)
      :Inventory Reserved;
      -> Inventory Check OK;
    else (No)
      :Insufficient Stock;
      -> Inventory Check Failed;
    endif
  }
fork again
  partition "Payment Service" {
    :Process Payment Authorization;
    note right: Integrates with external Payment Gateway
    if (Payment Authorized?) then (Yes)
      :Payment Authorized;
      -> Payment OK;
    else (No)
      :Payment Failed;
      -> Payment Failed;
    endif
  }
join

partition "Order Service" {
  if (Payment OK AND Inventory Check OK) then (Yes)
    :Update Order Status to "Processing";
    -> Order Processing;
  else (No)
    :Update Order Status to "Failed/Cancelled";
    partition "Inventory Service" {
      :Release Reserved Stock (if any);
    }
    partition "Notification Service" {
      :Send Order Failure Notification;
      note right: Via Kafka Event
    }
    stop
  endif
}

partition "Shipping Service" {
  :Calculate Shipping Costs;
  -> Shipping Costs Calculated;
}

fork
  partition "Inventory Service" {
    :Publish "Inventory Deducted" Event;
    note right: Via Kafka
  }
fork again
  partition "Notification Service" {
    :Send Order Confirmation Email/SMS;
    note right: Via Kafka Event
  }
fork again
  partition "Shipping Service" {
    :Publish "Shipment Ready" Event;
    note right: Via Kafka
  }
join

partition "Order Service" {
  :Mark Order as "Completed";
}

stop
@enduml

diagram_versions.interaction overview diagram:
@startuml
title E-commerce System Interaction Overview

start

partition "User Actions" {
  call "User Authentication" as AuthInteraction
  AuthInteraction --> call "Browse & Search Products" as BrowseInteraction
  BrowseInteraction --> call "Manage Shopping Cart" as CartInteraction
}

CartInteraction --> if (Shopping Cart has items?) then (Yes)
  partition "System Orchestration" {
    call "Checkout Process" as CheckoutInteraction
    CheckoutInteraction --> call "View Order History & Status" as OrderHistoryInteraction
    OrderHistoryInteraction --> call "Submit Product Review" as ReviewInteraction
  }
  ReviewInteraction --> stop
else (No)
  -> BrowseInteraction
endif

@enduml
